final:
module top_module(
    input               clk,
    input    [31:0]     in_data,

    output              gpio_sinal,
    output              mem_sinal
);reg                     gpio_flag;

always @(posedge clk)
begin
    if(in_data>1023) gpio_flag <= 1;
    else gpio_flag <= 0;
end

assign gpio_sinal = gpio_flag;
assign mem_sinal = ~gpio_flag;

endmodule
